 80	 *   1. `Content.getForm(form)` → the form's `FormDefinition`;
 81	 *   2. `decodeForm(definition, submission.payload)` → on failure,
 82	 *      `formValidationError(formatSchemaResult(...))` (bucketed field/form errors);
 83	 *   3. `notify(decoded)` — the caller's form-specific notification;
 84	 *   4. `toast.redirect(pathname, { success copy, form })`.
 85	 */
 86	export const formAction = <E>(config: FormActionConfig<E>) =>
 87	  routeFormAction(function* () {
