100	    yield* config.notify(decoded.success);
101	
102	    yield* toast.redirect(url.pathname, {
103	      title: config.success.title,
104	      description: config.success.description,
105	      type: 'success',
106	      form: config.form,
107	    });
108	    return { reset: true } satisfies FormSuccess;
109	  });

