46	/**
47	 * Parse an unknown payload with an Effect Schema, returning a {@link Result}
48	 * for conform consumption. Pair with {@link formatSchemaResult} in a route
49	 * action to bucket failures into form/field errors. The failure channel is a
50	 * {@link Issue} (beta.60 `decodeUnknownResult` returns the issue tree directly,
51	 * not a wrapping `SchemaError`).
52	 */
53	export const parseSchema = <A, I>(
54	  schema: Schema.Codec<A, I, never, never>,
55	  payload: unknown,
56	): Result.Result<A, Issue> => Schema.decodeUnknownResult(schema)(payload);
57	
58	/**
59	 * Convert an Effect Schema parse {@link Result} into conform's
60	 * `{ formErrors, fieldErrors }` shape. Returns `null` on success (conform's
61	 * convention for "no errors"). Issues with no path become form-level errors;
62	 * the rest are keyed by their {@link issuePathToName conform field name}.
63	 */
64	export const formatSchemaResult = <A>(
65	  result: Result.Result<A, Issue>,
66	): FormValidationErrorInput | null => {
67	  if (Result.isSuccess(result)) return null;
68	
69	  const issues = formatter(result.failure).issues;
70	  const formErrors: string[] = [];
71	  const fieldErrors: Record<string, string[]> = {};
72	
73	  for (const issue of issues) {
74	    const name = issuePathToName(issue.path);
75	    if (name === '') {
76	      formErrors.push(issue.message);
77	    } else {
78	      const existing = fieldErrors[name];
79	      if (existing) {
80	        existing.push(issue.message);
81	      } else {
82	        fieldErrors[name] = [issue.message];
83	      }
84	    }
85	  }
86	
87	  return { formErrors, fieldErrors } satisfies FormSchemaError;
88	};

