  2	import { parseSubmission, report } from '@conform-to/react/future';
  3	import { Context, Effect } from 'effect';
  4	
  5	import { isHoneypotTriggered } from '../honeypot';
  6	import {
  7	  BadRequestError,
  8	  FormValidationError,
  9	  InternalServerError,
 10	  NotFoundError,
 11	  RedirectError,
 12	} from './errors';
 13	import { ReactRouterContext, type RouteArgs } from './router-context';
 14	import type { AppError, AppServices } from './runtime';
 15	
 16	/**
 17	 * The parsed conform `/future` {@link Submission} for the in-flight form
 18	 * action. Provided by {@link routeFormAction} so the action body — and the
 19	 * Effect Schema validation helpers — can reach the submission without threading
 20	 * it through arguments.
 21	 */
 22	export class SubmissionContext extends Context.Service<
 23	  SubmissionContext,
 24	  Submission
 25	>()('gycc/lib/effect/form/SubmissionContext') {}
 26	
 27	/**
 28	 * Services available inside a {@link routeFormAction} body: everything a normal
 29	 * route effect has, plus the {@link SubmissionContext}.
 30	 */
 31	export type FormServices = AppServices | ReactRouterContext | SubmissionContext;
 32	
 33	/**
 34	 * What a form-action body returns on the happy path. `reset` tells conform
 35	 * whether to clear the form after a successful submit.
 36	 */
 37	export interface FormSuccess {
 38	  readonly reset: boolean;
 39	}
 40	
 41	/**
 42	 * The value a {@link routeFormAction} resolves to — a conform
 43	 * {@link SubmissionResult} plus a discriminant the client uses to branch on
 44	 * success vs. validation failure. `useForm({ lastResult })` consumes the
 45	 * `result`; the client reads `status` to drive its own post-submit UX.
 46	 */
 47	export type FormResult = {
 48	  readonly result: SubmissionResult<string[]>;
 49	  readonly status: 'success' | 'error';
 50	};
 51	
 52	/** Build a successful {@link FormResult} from the body's `reset` flag. */
 53	const successResult = (submission: Submission, reset: boolean): FormResult => ({
 54	  result: report(submission, { reset }),
 55	  status: 'success',
 56	});
 57	
 58	/** Build the error-status {@link FormResult} for a set of form-level messages. */
 59	const formLevelError = (submission: Submission, message: string): FormResult => ({
 60	  result: report(submission, { error: { formErrors: [message] } }),
 61	  status: 'error',
 62	});
 63	
 64	/** Build the error-status {@link FormResult} from validation error buckets. */
 65	const validationResult = (
 66	  submission: Submission,
 67	  error: FormValidationError['error'],
 68	): FormResult => ({
 69	  result: report(submission, {
 70	    error: {
 71	      // Schema yields readonly arrays; conform's `report` wants mutable ones.
 72	      formErrors: error.formErrors ? [...error.formErrors] : undefined,
 73	      fieldErrors: error.fieldErrors
 74	        ? Object.fromEntries(
 75	            Object.entries(error.fieldErrors).map(([key, value]) => [
 76	              key,
 77	              [...value],
 78	            ]),
 79	          )
 80	        : undefined,
 81	    },
 82	  }),
 83	  status: 'error',
 84	});
 85	
 86	/**
 87	 * Map a body failure onto a {@link FormResult}, or re-fail it for the runtime.
 88	 *
 89	 * {@link RedirectError} re-fails so the runtime maps it to a redirect
 90	 * `Response` (C1), letting a successful submit redirect with a flash toast.
 91	 * Validation / request errors become form-level (or field-level) error reports.
 92	 * Anything else (mailer/sendgrid failures, raw `Response`) re-fails to the
 93	 * runtime's generic handling.
 94	 */
 95	const handleFormError = (
 96	  submission: Submission,
 97	  error: AppError,
 98	): Effect.Effect<FormResult, AppError> => {
 99	  if (RedirectError.is(error)) return Effect.fail(error);
100	  if (FormValidationError.is(error)) {
101	    return Effect.succeed(validationResult(submission, error.error));
102	  }
103	  if (BadRequestError.is(error)) {
104	    return Effect.succeed(
105	      formLevelError(submission, error.message || 'Bad request'),
106	    );
107	  }
108	  if (NotFoundError.is(error)) {
109	    return Effect.succeed(formLevelError(submission, 'Not found'));
110	  }
111	  if (InternalServerError.is(error)) {
112	    return Effect.succeed(formLevelError(submission, 'An error occurred'));
113	  }
114	  return Effect.fail(error);
115	};
116	
117	/**
118	 * Conform-based action wrapper. Sits alongside {@link routeHandler} /
119	 * `routeAction` (which run arbitrary loader/non-form effects); use
120	 * `routeFormAction` for conform forms that must return a {@link FormResult}.
121	 *
122	 * Pipeline (modeled on bureau's `runtime.server.ts form()`, minus intent
123	 * dispatch):
124	 * 1. Parse `request.formData()` and {@link parseSubmission}. A parse failure
125	 *    fails with {@link BadRequestError} — there is no submission to report
126	 *    against, so it propagates to the runtime and is mapped to a 400 (C1).
127	 * 2. Provide the {@link SubmissionContext} and run the body generator.
128	 * 3. Success → `report(submission, { reset })`, `status: 'success'`.
129	 * 4. Failures are bucketed by {@link handleFormError}: validation/request
130	 *    errors become form/field error reports; redirects propagate via C1.
131	 */
132	export const routeFormAction =
133	  <Eff extends Effect.Yieldable<any, any, any, FormServices>>(
134	    body: () => Generator<Eff, FormSuccess, never>,
135	  ) =>
136	  (args: RouteArgs): Promise<FormResult> => {
137	    const pipeline: Effect.Effect<
138	      FormResult,
139	      AppError,
140	      AppServices | ReactRouterContext
141	    > = Effect.gen(function* () {
142	      const reactRouter = yield* ReactRouterContext;
143	      const formData = yield* Effect.tryPromise({
144	        try: () => reactRouter.request.formData(),
145	        catch: (cause) =>
146	          new BadRequestError({
147	            message:
148	              cause instanceof Error ? cause.message : 'Unable to read form data',
149	          }),
150	      });
151	      const submission = yield* Effect.try({
152	        try: () => parseSubmission(formData),
153	        catch: (cause) =>
154	          new BadRequestError({
155	            message:
156	              cause instanceof Error
157	                ? cause.message
158	                : 'Unable to parse form submission',
159	          }),
160	      });
161	
162	      if (isHoneypotTriggered(formData)) {
163	        yield* Effect.logInfo('Honeypot triggered');
164	        return successResult(submission, true);
165	      }
166	
167	      const bodyEffect = Effect.gen(body) as Effect.Effect<
168	        FormSuccess,
169	        AppError,
170	        FormServices
171	      >;
172	
173	      return yield* bodyEffect.pipe(
174	        Effect.provideService(SubmissionContext, submission),
175	        Effect.map(({ reset }) => successResult(submission, reset)),
176	        Effect.catch((error) => handleFormError(submission, error)),
177	      );
178	    });
179	
180	    return args.context.runtime.run(args, pipeline);
181	  };

