 12	/**
 13	 * Branch 6.2 — the generic action skeleton.
 14	 *
 15	 * `formAction({ form, notify, success })` collapses the `parse → decode → notify
 16	 * → toast.redirect` pipeline the three form routes triplicate into one wrapped
 17	 * route action. These tests pin the pipeline WIRING (`prove-it-works`) — the
 18	 * per-kind decode semantics are covered exhaustively in `decode.test.ts`, so here
 19	 * the form's `FormDefinition` is the bundled default (empty field graph, so any
 20	 * payload decodes), letting the test isolate the skeleton's own behaviour:
 21	 *   - a valid submission runs `notify` with the decoded payload, then redirects
 22	 *     with the success toast (so a migrated route's success path is unchanged);
 23	 *   - a `notify` failure (e.g. a mailer error mapped to a form-level key) aborts
 24	 *     the redirect and surfaces as a form error report — the record-vs-notify
 25	 *     separation Branch 7 builds the persist step in front of;
 26	 *   - the honeypot short-circuit (inherited from `routeFormAction`) skips the
 27	 *     body entirely.
 28	 *
 29	 * The action runs through the real request runtime (`makeRequestRuntime`), which
 30	 * wires `Content` (reading the bundled default form definition), `Toast`, and the
 31	 * `Mailer` — the same layers the live server provides.
 32	 */
 33	
 34	const makeFormArgs = (fields: Record<string, string>): RouteArgs => {
 35	  const body = new URLSearchParams(fields);
 36	  const url = 'http://localhost/contact';
 37	  const request = new Request(url, {
 38	    method: 'POST',
 39	    body,
 40	    headers: { 'content-type': 'application/x-www-form-urlencoded' },
 41	  });
 42	  const context = new RouterContextProvider();
 43	  context.runtime = makeRequestRuntime();
 44	  return {
 45	    request,
 46	    url: new URL(url),
 47	    pattern: '/contact',
 48	    params: {},
 49	    context,
 50	  };
 51	};
