 53	describe('formAction', () => {
 54	  it('runs notify with the decoded payload, then redirects with the success toast', async () => {
 55	    let notified: DecodedForm | undefined;
 56	    const action = formAction({
 57	      form: 'contact',
 58	      notify: (decoded) =>
 59	        Effect.sync(() => {
 60	          notified = decoded;
 61	        }),
 62	      success: {
 63	        title: 'contact.form.success.title',
 64	        description: 'contact.form.success.description',
 65	      },
 66	    });
 67	
 68	    let thrown: unknown;
 69	    try {
 70	      await action(makeFormArgs({ name: 'Ada' }));
 71	    } catch (error) {
 72	      thrown = error;
 73	    }
 74	
 75	    // The terminal toast.redirect fails with a RedirectError the runtime maps to
 76	    // a redirect Response (the C1 mapping the contact/volunteer actions rely on).
 77	    expect(thrown).toBeInstanceOf(Response);
 78	    const response = thrown as Response;
 79	    expect(response.status).toBe(302);
 80	    expect(response.headers.get('location')).toBe('/contact');
 81	    // The success toast was flashed (the set-cookie carries the toast session).
 82	    expect(response.headers.get('set-cookie')).toContain('toast');
 83	    // notify ran with the decoded payload.
 84	    expect(notified).toEqual({ name: 'Ada' });
 85	  });
 86	
 87	  it('a notify failure aborts the redirect and reports a form-level error', async () => {
 88	    const action = formAction({
 89	      form: 'contact',
 90	      notify: () =>
 91	        Effect.fail(formValidationError({ formErrors: ['contact.form.error'] })),
 92	      success: {
 93	        title: 'contact.form.success.title',
 94	        description: 'contact.form.success.description',
 95	      },
 96	    });
 97	
 98	    const result = await action(makeFormArgs({ name: 'Ada' }));
 99	
100	    expect(result.status).toBe('error');
101	    expect(result.result.error?.formErrors).toEqual(['contact.form.error']);
102	  });
103	
104	  it('skips the body (no notify) when the honeypot is filled', async () => {
105	    let notifyRan = false;
106	    const action = formAction({
107	      form: 'contact',
108	      notify: () =>
109	        Effect.sync(() => {
110	          notifyRan = true;
111	        }),
112	      success: {
113	        title: 'contact.form.success.title',
114	        description: 'contact.form.success.description',
115	      },
116	    });
117	
118	    const result = await action(
119	      makeFormArgs({ name: 'Ada', website: 'https://spam.example' }),
120	    );
121	
122	    expect(notifyRan).toBe(false);
123	    expect(result.status).toBe('success');
124	  });
125	});

